css:
* { margin: 0; padding: 0; box-sizing: border-box; }
body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; background: #f0fdff; color: #0c4a6e; }
nav { display: flex; align-items: center; justify-content: space-between; padding: 0 72px; height: 72px; background: white; border-bottom: 1px solid #e0f7ff; position: sticky; top: 0; z-index: 100; }
.logo { font-size: 20px; font-weight: 800; color: #0891b2; }
.links { display: flex; gap: 28px; } .links a { color: #6b7280; text-decoration: none; font-weight: 500; font-size: 14px; } .links a:hover { color: #0891b2; }
.appointment-btn { padding: 12px 24px; border-radius: 12px; border: none; background: linear-gradient(135deg, #06b6d4, #0891b2); color: white; font-weight: 700; cursor: pointer; }
.hero { display: grid; grid-template-columns: 1fr 1fr; gap: 60px; align-items: center; padding: 80px 72px; min-height: calc(100vh - 72px); }
.tag { display: inline-block; color: #0891b2; font-size: 13px; font-weight: 700; letter-spacing: 2px; margin-bottom: 20px; }
h1 { font-size: 64px; font-weight: 900; line-height: 1; letter-spacing: -2px; margin-bottom: 20px; color: #0c4a6e; } h1 span { color: #06b6d4; }
.hero-left p { color: #6b7280; font-size: 17px; line-height: 1.7; margin-bottom: 28px; max-width: 440px; }
.hero-btns { display: flex; gap: 14px; margin-bottom: 32px; }
.btn-main { padding: 16px 32px; border-radius: 14px; border: none; background: linear-gradient(135deg, #06b6d4, #0891b2); color: white; font-weight: 800; font-size: 15px; cursor: pointer; box-shadow: 0 12px 28px rgba(6,182,212,0.3); }
.btn-outline { padding: 16px 28px; border-radius: 14px; border: 2px solid #06b6d4; background: transparent; color: #0891b2; font-weight: 700; font-size: 15px; cursor: pointer; }
.trust-badges { display: flex; gap: 28px; }
.tb { } .tb strong { display: block; font-size: 28px; font-weight: 900; color: #06b6d4; } .tb span { color: #6b7280; font-size: 13px; }
.health-card { background: white; border-radius: 24px; padding: 24px; box-shadow: 0 20px 60px rgba(6,182,212,0.12); border: 1px solid #e0f7ff; }
.hc-header { font-size: 14px; font-weight: 700; color: #0891b2; margin-bottom: 16px; }
.appointment-item { display: flex; align-items: center; gap: 12px; padding: 12px 0; border-bottom: 1px solid #f0fdff; }
.ai-icon { font-size: 24px; width: 40px; height: 40px; border-radius: 12px; background: #e0f7ff; display: flex; align-items: center; justify-content: center; }
.ai-info { flex: 1; } .ai-info strong { display: block; font-size: 14px; font-weight: 700; color: #0c4a6e; } .ai-info small { color: #6b7280; font-size: 12px; }
.ai-status { color: #22c55e; font-size: 16px; font-weight: 800; } .ai-status.pending { color: #eab308; }
.health-metrics { display: flex; gap: 12px; margin-top: 16px; }
.hm-item { flex: 1; background: #f0fdff; border-radius: 12px; padding: 12px; display: flex; gap: 8px; align-items: center; }
.hm-icon { font-size: 18px; } .hm-item strong { display: block; font-size: 15px; font-weight: 800; color: #0c4a6e; } .hm-item small { color: #6b7280; font-size: 11px; }
.services { padding: 80px 72px; background: white; border-top: 1px solid #e0f7ff; } .services h2 { font-size: 40px; font-weight: 800; margin-bottom: 36px; color: #0c4a6e; }
.services-grid { display: grid; grid-template-columns: repeat(4,1fr); gap: 20px; }
.service-card { padding: 28px; border-radius: 18px; background: #f0fdff; border: 1px solid #e0f7ff; text-align: center; transition: all 0.2s; cursor: pointer; } .service-card:hover { border-color: #06b6d4; transform: translateY(-3px); box-shadow: 0 8px 20px rgba(6,182,212,0.12); }
.sc-icon { font-size: 36px; margin-bottom: 14px; } .service-card h3 { font-size: 17px; font-weight: 700; color: #0c4a6e; margin-bottom: 8px; } .service-card p { color: #6b7280; font-size: 13px; line-height: 1.6; }
.modal { position: fixed; inset: 0; background: rgba(0,0,0,0.5); z-index: 200; display: flex; align-items: center; justify-content: center; backdrop-filter: blur(6px); }
.modal-card { background: white; border-radius: 24px; padding: 0; width: 480px; overflow: hidden; }
.modal-header { display: flex; justify-content: space-between; align-items: center; padding: 20px 24px; background: linear-gradient(135deg, #06b6d4, #0891b2); color: white; } .modal-header h3 { font-size: 18px; font-weight: 800; } .modal-header button { background: rgba(255,255,255,0.2); border: none; color: white; width: 32px; height: 32px; border-radius: 50%; cursor: pointer; font-size: 16px; }
.modal-body { padding: 24px; display: flex; flex-direction: column; gap: 14px; }
.form-group label { display: block; font-size: 13px; font-weight: 700; color: #0891b2; margin-bottom: 6px; }
.form-group input, .form-group select { width: 100%; height: 44px; border-radius: 10px; border: 1px solid #e0f7ff; background: #f0fdff; padding: 0 14px; font-size: 14px; color: #0c4a6e; outline: none; } input:focus, select:focus { border-color: #06b6d4; }
.submit-btn { height: 50px; border-radius: 14px; border: none; background: linear-gradient(135deg, #06b6d4, #0891b2); color: white; font-size: 16px; font-weight: 800; cursor: pointer; }

js:
function openModal() { document.getElementById('modal').style.display='flex'; }
function closeModal() { document.getElementById('modal').style.display='none'; }
function submitAppointment() {
  const btn = document.querySelector('.submit-btn');
  btn.textContent = '✓ Randevunuz Onaylandı!';
  btn.style.background = '#22c55e';
  setTimeout(() => { closeModal(); btn.textContent='Randevuyu Onayla'; btn.style.background=''; }, 2000);
}
document.getElementById('modal').addEventListener('click', function(e) { if (e.target === this) closeModal(); });
